import functions_framework
import pymysql
import os
import json

DB_HOST = os.environ.get('DB_HOST', 'localhost')
DB_USER = os.environ.get('DB_USER', 'root')
DB_PASSWORD = os.environ.get('DB_PASSWORD', '')
DB_NAME = os.environ.get('DB_NAME', 'mydb')
DB_PORT = int(os.environ.get('DB_PORT', 3306))

def get_db_connection():
    return pymysql.connect(
        host=DB_HOST,
        user=DB_USER,
        password=DB_PASSWORD,
        database=DB_NAME,
        port=DB_PORT,
        cursorclass=pymysql.cursors.DictCursor
    )

@functions_framework.http
def search_api(request):
    try:
        params = request.args.to_dict()
        
        table = params.get('table', 'users')
        fields = params.get('fields', '*')
        limit = params.get('limit', '100')
        offset = params.get('offset', '0')
        order_by = params.get('order_by', '')
        order_dir = params.get('order_dir', 'ASC')
        
        base_query = f"SELECT {fields} FROM {table}"
        
        where_clauses = []
        search_params = {k: v for k, v in params.items() 
                        if k not in ['table', 'fields', 'limit', 'offset', 'order_by', 'order_dir', 'operator']}
        
        operator = params.get('operator', 'AND')
        
        for key, value in search_params.items():
            if ',' in value:
                values = value.split(',')
                in_clause = ','.join([f"'{v}'" for v in values])
                where_clauses.append(f"{key} IN ({in_clause})")
            elif value.startswith('%') or value.endswith('%'):
                where_clauses.append(f"{key} LIKE '{value}'")
            elif value.startswith('>') or value.startswith('<') or value.startswith('>=') or value.startswith('<='):
                where_clauses.append(f"{key} {value}")
            else:
                where_clauses.append(f"{key} = '{value}'")
        
        if where_clauses:
            base_query += f" WHERE {f' {operator} '.join(where_clauses)}"
        
        if order_by:
            base_query += f" ORDER BY {order_by} {order_dir}"
        
        base_query += f" LIMIT {limit} OFFSET {offset}"
        
        connection = get_db_connection()
        try:
            with connection.cursor() as cursor:
                cursor.execute(base_query)
                results = cursor.fetchall()
                
                return {
                    'status': 'success',
                    'query': base_query,
                    'count': len(results),
                    'data': results
                }, 200, {'Content-Type': 'application/json'}
        finally:
            connection.close()
            
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }, 500, {'Content-Type': 'application/json'}